const body = $input.item.json.body || $input.item.json;
const msg = body.message || body.edited_message || {};
const chat_id = String(msg.chat?.id || '');
const user_id = String(msg.from?.id || chat_id);
const user_name = msg.from?.first_name || msg.from?.username || 'Usuario';
const text = (msg.text || '').trim();

if (!chat_id || !text) return [];

// Detectar si es comando explícito
const is_command = text.startsWith('/');
let command = 'unknown';
let parameter = '';

if (is_command) {
  const parts = text.split(/\s+/);
  command = parts[0].toLowerCase().split('@')[0];
  parameter = parts.slice(1).join(' ').trim();
}

return [{ json: { chat_id, user_id, user_name, text, command, parameter, is_command } }];

const { text } = $input.item.json;

const prompt = `Analiza el siguiente mensaje de un usuario en Telegram para un asistente de Copywriting y determina su intención exacta.

COMANDOS DISPONIBLES:
- /setup [file_id]: Si el usuario quiere configurar su perfil o menciona cargar un archivo/id de Google Drive.
- /copy [tema]: Si el usuario pide generar un copy, escribir algo nuevo o da un tema.
- /copy_hoy: Si el usuario quiere el copy de hoy o pregunta qué toca publicar hoy.
- /stats: Si el usuario quiere ver estadísticas, rendimiento o qué ha hecho.
- /pattern: Si el usuario quiere ver su patrón de escritura o estilo.
- /help: Si el usuario está perdido o pide ayuda.
- /reset: Si el usuario quiere borrar todo o reiniciar.

Reglas:
1. Responde ÚNICAMENTE con un JSON válido.
2. El JSON debe tener: { "command": "/comando", "parameter": "texto adicional o id" }.
3. Si el usuario solo da un tema (ej: "nutrición"), asume /copy.

MENSAJE DEL USUARIO:
"${text}"

JSON:`;

const body = { 
  contents: [{ parts: [{ text: prompt }] }], 
  generationConfig: { temperature: 0.1, maxOutputTokens: 200 }
};

return [{ json: { ...$input.item.json, gemini_intent_body: JSON.stringify(body) } }];

const raw = $input.item.json;
let text = '';
try { text = raw.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch(e) {}
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let result = { command: '/copy', parameter: '' };
try {
  result = JSON.parse(text);
} catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { result = JSON.parse(m[0]); } catch(e2) {} }
}

const original = $('Check Format').item.json;
return [{ json: { ...original, command: result.command, parameter: result.parameter, is_command: true } }];

const parsed = $('Router Comandos').item.json;
const binary = $input.item.binary || {};
let notebookContent = '';
const binaryKey = Object.keys(binary)[0];
if (binaryKey) {
  notebookContent = Buffer.from(binary[binaryKey].data, 'base64').toString('utf-8');
}
if (!notebookContent) notebookContent = parsed.parameter || 'Sin contenido';
return [{ json: { chat_id: parsed.chat_id, user_id: parsed.user_id, user_name: parsed.user_name, notebook_content: notebookContent } }];

const { chat_id, user_id, user_name, notebook_content } = $input.item.json;

const prompt = `Eres un experto extrayendo información estructurada de notebooks de marketing.

Analiza el siguiente notebook y extrae EXACTAMENTE esta información. Devuelve SOLO JSON válido sin markdown:

{
  "informacion_general": {
    "nombre": "nombre de la agencia",
    "nicho": "nicho principal",
    "publico_objetivo": "descripción del público",
    "valores": ["valor1", "valor2"],
    "diferenciador": "diferenciador único"
  },
  "copys_mejores": [{"id": 1, "titulo": "Copy #1", "contenido": "texto completo"}],
  "patron_estructura": {
    "tipo_gancho": "Pregunta/Historia/Estadística/Afirmación",
    "estructura_desarrollo": "Problema → Solución → Proof",
    "tipo_cierre": "CTA directo/Pregunta/Reflexión",
    "tono_general": "descripción del tono",
    "palabras_clave": ["palabra1", "palabra2"],
    "emociones": ["esperanza", "urgencia"]
  },
  "plan_diario": {"lunes": "tema", "martes": "tema", "miercoles": "tema", "jueves": "tema", "viernes": "tema", "sabado": "tema", "domingo": "tema"},
  "formato_final": {"min_palabras": 150, "max_palabras": 300, "estructura_visual": "descripción", "cantidad_emojis": 3, "tipo_parrafos": "cortos"}
}

NOTEBOOK:
${notebook_content}`;

const body = { contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.3, maxOutputTokens: 2000 } };

return [{ json: { chat_id, user_id, user_name, gemini_body: JSON.stringify(body) } }];

const prev = $('Build Extract Body').item.json;
const raw = $input.item.json;

let text = '';
try { text = raw.candidates?.[0]?.content?.parts?.[0]?.text || ''; } catch(e) {}
text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let clientData = {};
try {
  clientData = JSON.parse(text);
} catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { clientData = JSON.parse(m[0]); } catch(e2) {} }
}

return [{ json: { chat_id: prev.chat_id, user_id: prev.user_id, user_name: prev.user_name, client_data: clientData, parse_ok: Object.keys(clientData).length > 0 } }];

const d = $('Parse Extract Response').item.json;
const cd = d.client_data || {};
const gi = cd.informacion_general || {};
const p = cd.patron_estructura || {};
const copys = cd.copys_mejores || [];

const msg = `✅ SETUP COMPLETADO

He analizado y guardé tu perfil:

📊 Nombre: ${gi.nombre || 'N/A'}
🎯 Nicho: ${gi.nicho || 'N/A'}
🗣 Tono: ${p.tono_general || 'N/A'}
🪝 Gancho típico: ${p.tipo_gancho || 'N/A'}
📝 Copys analizados: ${copys.length}

COMANDOS:
/copy [tema] → Genera copy
/copy_hoy → Copy del día
/stats → Estadísticas
/pattern → Ver tu patrón
/reset → Borrar y reiniciar`;

return [{ json: { chat_id: d.chat_id, message_text: msg } }];

const parsed = $('Router Comandos').item.json;
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const cliente = rows[0] || null;

if (!cliente) {
  return [{ json: { chat_id: parsed.chat_id, no_client: true, gemini_body: '' } }];
}

const patron = cliente.patron_estructura || {};
const copys = (cliente.copys_mejores || []).map((c, i) => `COPY ${i+1}:
${c.contenido || c}`).join('

---

');
const formato = cliente.formato_final || {};
const tema = parsed.parameter || 'general';

const prompt = `ERES UN EXPERTO GENERADOR DE COPYS CON PATRÓN EXACTO

PATRÓN DEL CLIENTE:
${JSON.stringify(patron, null, 2)}

COPYS DE REFERENCIA:
${copys}

FORMATO:
- Mínimo: ${formato.min_palabras || 150} palabras
- Máximo: ${formato.max_palabras || 300} palabras
- Emojis: ${formato.cantidad_emojis || 3}
- Párrafos: ${formato.tipo_parrafos || 'cortos'}

PALABRAS CLAVE A INCLUIR: ${(patron.palabras_clave || []).join(', ')}
EMOCIONES A TOCAR: ${(patron.emociones || []).join(', ')}

TEMA: ${tema}

Reglas:
✓ Mismo tipo de gancho
✓ Misma estructura
✓ Mismo tono
✓ Devuelve SOLO el copy, sin análisis

COPY FINAL:`;

const body = { contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.8, maxOutputTokens: 2500 } };

return [{ json: { chat_id: parsed.chat_id, user_id: parsed.user_id, tema, no_client: false, gemini_body: JSON.stringify(body) } }];

const prev = $('Build Generate Body').item.json;
const raw = $input.item.json;

if (prev.no_client) {
  return [{ json: { chat_id: prev.chat_id, copy_text: '⚠️ No tienes perfil configurado. Usa /setup [file_id] para comenzar.', tema: '', is_copy: false } }];
}

const copyText = (raw.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
return [{ json: { chat_id: prev.chat_id, user_id: prev.user_id, tema: prev.tema, copy_text: copyText || '⚠️ Error al generar. Intenta de nuevo.', is_copy: !!copyText } }];

const d = $('Extract Copy').item.json;
const footer = d.is_copy ? '

─────
📋 /copy_hoy para el de hoy | /stats para ver más' : '';
return [{ json: { chat_id: d.chat_id, message_text: d.copy_text + footer } }];

const parsed = $('Router Comandos').item.json;
const dias = { 0: 'domingo', 1: 'lunes', 2: 'martes', 3: 'miercoles', 4: 'jueves', 5: 'viernes', 6: 'sabado' };
const dia_hoy = dias[new Date().getDay()];
return [{ json: { ...parsed, dia_hoy } }];

const getDay = $('Get Day').item.json;
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const cliente = rows[0] || null;

if (!cliente) {
  return [{ json: { chat_id: getDay.chat_id, no_client: true, gemini_body: '', dia_hoy: getDay.dia_hoy, tema: '' } }];
}

const planDiario = cliente.plan_diario || {};
const tema = planDiario[getDay.dia_hoy] || getDay.dia_hoy || 'general';
const patron = cliente.patron_estructura || {};
const copys = (cliente.copys_mejores || []).map((c, i) => `COPY ${i+1}:
${c.contenido || c}`).join('

---

');
const formato = cliente.formato_final || {};

const prompt = `ERES UN EXPERTO GENERADOR DE COPYS CON PATRÓN EXACTO

PATRÓN DEL CLIENTE:
${JSON.stringify(patron, null, 2)}

COPYS DE REFERENCIA:
${copys}

FORMATO:
- Mínimo: ${formato.min_palabras || 150} palabras
- Máximo: ${formato.max_palabras || 300} palabras
- Emojis: ${formato.cantidad_emojis || 3}
- Párrafos: ${formato.tipo_parrafos || 'cortos'}

TEMA DEL DÍA (${getDay.dia_hoy.toUpperCase()}): ${tema}

Genera el copy siguiendo exactamente el patrón. Devuelve SOLO el copy.

COPY FINAL:`;

const body = { contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.8, maxOutputTokens: 2500 } };

return [{ json: { chat_id: getDay.chat_id, user_id: getDay.user_id, dia_hoy: getDay.dia_hoy, tema, no_client: false, gemini_body: JSON.stringify(body) } }];

const prev = $('Build Generate Hoy Body').item.json;
const raw = $input.item.json;

if (prev.no_client) {
  return [{ json: { chat_id: prev.chat_id, copy_text: '⚠️ No tienes perfil configurado. Usa /setup [file_id] para comenzar.', dia_hoy: prev.dia_hoy, tema: '', is_copy: false } }];
}

const copyText = (raw.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
return [{ json: { chat_id: prev.chat_id, user_id: prev.user_id, dia_hoy: prev.dia_hoy, tema: prev.tema, copy_text: copyText || '⚠️ Error al generar. Intenta de nuevo.', is_copy: !!copyText } }];

const d = $('Extract Copy Hoy').item.json;
const diaLabel = d.dia_hoy ? d.dia_hoy.charAt(0).toUpperCase() + d.dia_hoy.slice(1) : '';
const header = d.is_copy ? `📅 Copy de hoy (${diaLabel}): ${d.tema}

` : '';
const footer = d.is_copy ? '

─────
¿Otro tema? Usa /copy [tema]' : '';
return [{ json: { chat_id: d.chat_id, message_text: header + d.copy_text + footer } }];

const parsed = $('Router Comandos').item.json;
const rows = Array.isArray($input.item.json) ? $input.item.json : [];

if (rows.length === 0) {
  return [{ json: { chat_id: parsed.chat_id, message_text: '📊 Aún no has generado copys. Usa /copy [tema] para comenzar.' } }];
}

const total = rows.length;
const semanaAtras = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const estaSemana = rows.filter(r => new Date(r.fecha) >= semanaAtras).length;

const temaCount = {};
rows.forEach(r => { const t = r.tema || 'general'; temaCount[t] = (temaCount[t] || 0) + 1; });

const temasStr = Object.entries(temaCount).sort((a,b) => b[1]-a[1]).slice(0,5).map(([t,c]) => `  • ${t}: ${c}`).join('\n');

const ultimo = rows[0];
const ultimaFecha = ultimo ? new Date(ultimo.fecha).toLocaleDateString('es-ES') : 'N/A';

const msg = `📊 ESTADÍSTICAS\n\n📝 Total copys: ${total}\n📅 Esta semana: ${estaSemana}\n🕐 Último: ${ultimaFecha} — ${ultimo?.tema || 'N/A'}\n\n🏷 Temas más usados:\n${temasStr}`;

return [{ json: { chat_id: parsed.chat_id, message_text: msg } }];

const parsed = $('Router Comandos').item.json;
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const cliente = rows[0] || null;

if (!cliente?.patron_estructura) {
  return [{ json: { chat_id: parsed.chat_id, message_text: '⚠️ No tienes perfil configurado. Usa /setup [file_id] para comenzar.' } }];
}

const p = cliente.patron_estructura;
const palabras = Array.isArray(p.palabras_clave) ? p.palabras_clave.join(', ') : (p.palabras_clave || 'N/A');
const emociones = Array.isArray(p.emociones) ? p.emociones.join(', ') : (p.emociones || 'N/A');

const msg = `🎯 TU PATRÓN DE ESCRITURA

📌 Cliente: ${cliente.cliente_nombre || 'N/A'}
🏷 Nicho: ${cliente.nicho || 'N/A'}

🪝 COMIENZAS CON:
→ ${p.tipo_gancho || 'N/A'}

📖 DESARROLLAS CON:
→ ${p.estructura_desarrollo || 'N/A'}

🎯 CIERRAS CON:
→ ${p.tipo_cierre || 'N/A'}

🗣 TONO:
→ ${p.tono_general || 'N/A'}

🔑 PALABRAS CLAVE:
→ ${palabras}

💡 EMOCIONES:
→ ${emociones}`;

return [{ json: { chat_id: parsed.chat_id, message_text: msg } }];
